content:
{
  "dialogues": [
    {
      "title": "如果下雨的話",
      "turns": [
        {
          "speaker": "A",
          "text": "明天如果下雨的話，我們就不要去公園了。",
          "pinyin": "Míngtiān rúguǒ xiàyǔ dehuà, wǒmen jiù bù yào qù gōngyuán le.",
          "pinyin_numeric": "ming2 tian1 ru2 guo3 xia4 yu3 de5 hua4, wo3 men5 jiu4 bu4 yao4 qu4 gong1 yuan2 le5.",
          "translation_en": "If it rains tomorrow, let's not go to the park.",
          "translation_ko": "내일 비가 오면 공원에 가지 말아요."
        },
        {
          "speaker": "B",
          "text": "好啊，那我們就去咖啡店喝咖啡，看書。",
          "pinyin": "Hǎo a, nà wǒmen jiù qù kāfēi diàn hē kāfēi, kàn shū.",
          "pinyin_numeric": "hao3 a5, na4 wo3 men5 jiu4 qu4 ka1 fei1 dian4 he1 ka1 fei1, kan4 shu1.",
          "translation_en": "Okay, then we'll go to a coffee shop to drink coffee and read books.",
          "translation_ko": "좋아요, 그럼 커피숍에 가서 커피 마시고 책을 봐요."
        },
        {
          "speaker": "A",
          "text": "要是沒下雨的話，我們就去公園散步。",
          "pinyin": "Yàoshi méi xiàyǔ dehuà, wǒmen jiù qù gōngyuán sànbù.",
          "pinyin_numeric": "yao4 shi4 mei2 xia4 yu3 de5 hua4, wo3 men5 jiu4 qu4 gong1 yuan2 san4 bu4.",
          "translation_en": "If it doesn't rain, we'll go for a walk in the park.",
          "translation_ko": "비가 안 오면 공원에 산책하러 가요."
        },
        {
          "speaker": "B",
          "text": "好，那我們先準備一下。萬一下雨的話，記得帶傘。",
          "pinyin": "Hǎo, nà wǒmen xiān zhǔnbèi yīxià. Wànyī xiàyǔ dehuà, jìde dài sǎn.",
          "pinyin_numeric": "hao3, na4 wo3 men5 xian1 zhun3 bei4 yi1 xia4. wan4 yi1 xia4 yu3 de5 hua4, ji4 de5 dai4 san3.",
          "translation_en": "Okay, let's prepare a bit. In case it rains, remember to bring an umbrella.",
          "translation_ko": "좋아요, 그럼 먼저 준비 좀 해요. 만약 비가 오면 우산 챙기는 거 잊지 마세요."
        },
        {
          "speaker": "A",
          "text": "沒問題，我會帶傘。如果天氣好的話，我們也可以去公園拍照。",
          "pinyin": "Méi wèntí, wǒ huì dài sǎn. Rúguǒ tiānqì hǎo dehuà, wǒmen yě kěyǐ qù gōngyuán pāizhào.",
          "pinyin_numeric": "mei2 wen4 ti2, wo3 hui4 dai4 san3. ru2 guo3 tian1 qi4 hao3 de5 hua4, wo3 men5 ye3 ke3 yi3 qu4 gong1 yuan2 pai1 zhao4.",
          "translation_en": "No problem, I'll bring an umbrella. If the weather is good, we can also take photos at the park.",
          "translation_ko": "문제없어요, 우산 챙길게요. 날씨가 좋으면 공원에서 사진도 찍을 수 있어요."
        }
      ],
      "comprehension_questions": [
        {
          "question_en": "What will they do if it rains?",
          "question_ko": "비가 오면 그들은 무엇을 할 예정인가요?",
          "options_en": ["Go to the park", "Go to a coffee shop", "Stay home"],
          "options_ko": ["공원에 가다", "커피숍에 가다", "집에 있다"],
          "correct_index": 1
        }
      ],
      "shadowing_prompt": "Repeat each sentence after the speaker, focusing on the conditional structure '如果...的話' and '要是...就'.",
      "free_response_prompt": "Say what you will do if it rains tomorrow. Use '如果...的話' or '要是...就'."
    },
    {
      "title": "如果遲到的話",
      "turns": [
        {
          "speaker": "A",
          "text": "明天我們約早上九點在車站見面。如果你遲到的話，我就先走了。",
          "pinyin": "Míngtiān wǒmen yuē zǎoshang jiǔ diǎn zài chēzhàn jiànmiàn. Rúguǒ nǐ chídào dehuà, wǒ jiù xiān zǒu le.",
          "pinyin_numeric": "ming2 tian1 wo3 men5 yue1 zao3 shang5 jiu3 dian3 zai4 che1 zhan4 jian4 mian4. ru2 guo3 ni3 chi2 dao4 de5 hua4, wo3 jiu4 xian1 zou3 le5.",
          "translation_en": "Tomorrow we agreed to meet at the station at 9 AM. If you're late, I'll leave first.",
          "translation_ko": "내일 아침 9시에 역에서 만나기로 했어요. 만약 늦으면 먼저 갈게요."
        },
        {
          "speaker": "B",
          "text": "抱歉，我不會遲到的。要是真的遲到的話，我會先打電話給你。",
          "pinyin": "Bàoqiàn, wǒ bù huì chídào de. Yàoshi zhēn de chídào dehuà, wǒ huì xiān dǎ diànhuà gěi nǐ.",
          "pinyin_numeric": "bao4 qian4, wo3 bu4 hui4 chi2 dao4 de5. yao4 shi4 zhen1 de5 chi2 dao4 de5 hua4, wo3 hui4 xian1 da3 dian4 hua4 gei3 ni3.",
          "translation_en": "Sorry, I won't be late. If I really am late, I'll call you first.",
          "translation_ko": "죄송합니다, 늦지 않을게요. 정말 늦으면 먼저 전화 드릴게요."
        },
        {
          "speaker": "A",
          "text": "好，那我們就約九點。萬一你遲到的話，我們就改時間。",
          "pinyin": "Hǎo, nà wǒmen jiù yuē jiǔ diǎn. Wànyī nǐ chídào dehuà, wǒmen jiù gǎi shíjiān.",
          "pinyin_numeric": "hao3, na4 wo3 men5 jiu4 yue1 jiu3 dian3. wan4 yi1 ni3 chi2 dao4 de5 hua4, wo3 men5 jiu4 gai3 shi2 jian1.",
          "translation_en": "Okay, let's meet at nine. In case you're late, we'll change the time.",
          "translation_ko": "좋아요, 그럼 9시로 약속해요. 만약 늦으면 시간을 바꿔요."
        },
        {
          "speaker": "B",
          "text": "沒問題，我會準時到。如果塞車的話，我會提早出門。",
          "pinyin": "Méi wèntí, wǒ huì zhǔnshí dào. Rúguǒ sāichē dehuà, wǒ huì tízǎo chūmén.",
          "pinyin_numeric": "mei2 wen4 ti2, wo3 hui4 zhun3 shi2 dao4. ru2 guo3 sai1 che1 de5 hua4, wo3 hui4 ti2 zao3 chu1 men2.",
          "translation_en": "No problem, I'll be on time. If there's a traffic jam, I'll leave early.",
          "translation_ko": "문제없어요, 정시에 도착할게요. 교통 체증이 있으면 일찍 나갈게요."
        }
      ],
      "comprehension_questions": [
        {
          "question_en": "What will A do if B is late?",
          "question_ko": "B가 늦으면 A는 무엇을 할 예정인가요?",
          "options_en": ["Wait for B", "Leave first", "Call B"],
          "options_ko": ["B를 기다리다", "먼저 가다", "B에게 전화하다"],
          "correct_index": 1
        }
      ],
      "shadowing_prompt": "Repeat each sentence after the speaker, focusing on the conditional structures '如果...的話' and '要是...就'.",
      "free_response_prompt": "Say what you will do if your friend is late for a meeting. Use '如果...的話' or '要是...就'."
    },
    {
      "title": "如果關門的話",
      "turns": [
        {
          "speaker": "A",
          "text": "我想去那家餐廳吃牛肉麵，可是如果關門的話，我們就去吃滷肉飯。",
          "pinyin": "Wǒ xiǎng qù nà jiā cāntīng chī niúròu miàn, kěshì rúguǒ guānmén dehuà, wǒmen jiù qù chī lǔròu fàn.",
          "pinyin_numeric": "wo3 xiang3 qu4 na4 jia1 can1 ting1 chi1 niu2 rou4 mian4, ke3 shi4 ru2 guo3 guan1 men2 de5 hua4, wo3 men5 jiu4 qu4 chi1 lu3 rou4 fan4.",
          "translation_en": "I want to go to that restaurant for beef noodles, but if it's closed, we'll go eat braised pork rice.",
          "translation_ko": "그 식당에 가서 소고기 국수를 먹고 싶은데, 문을 닫았으면 루로우판을 먹으러 가요."
        },
        {
          "speaker": "B",
          "text": "好啊，那我們先去看看。要是關門的話，我們就換一家。",
          "pinyin": "Hǎo a, nà wǒmen xiān qù kànkan. Yàoshi guānmén dehuà, wǒmen jiù huàn yī jiā.",
          "pinyin_numeric": "hao3 a5, na4 wo3 men5 xian1 qu4 kan4 kan5. yao4 shi4 guan1 men2 de5 hua4, wo3 men5 jiu4 huan4 yi1 jia1.",
          "translation_en": "Okay, let's go check first. If it's closed, we'll switch to another place.",
          "translation_ko": "좋아요, 그럼 먼저 가서 볼게요. 문을 닫았으면 다른 데로 바꿔요."
        },
        {
          "speaker": "A",
          "text": "萬一那家也關門的話，我們就回家自己煮。",
          "pinyin": "Wànyī nà jiā yě guānmén dehuà, wǒmen jiù huí jiā zìjǐ zhǔ.",
          "pinyin_numeric": "wan4 yi1 na4 jia1 ye3 guan1 men2 de5 hua4, wo3 men5 jiu4 hui2 jia1 zi4 ji3 zhu3.",
          "translation_en": "In case that place is also closed, we'll go home and cook ourselves.",
          "translation_ko": "만약 그 집도 문을 닫았으면 집에 가서 직접 요리해요."
        },
        {
          "speaker": "B",
          "text": "好，那我們先準備一下。如果關門的話，我們就去便利商店買東西吃。",
          "pinyin": "Hǎo, nà wǒmen xiān zhǔnbèi yīxià. Rúguǒ guānmén dehuà, wǒmen jiù qù biànlì shāngdiàn mǎi dōngxi chī.",
          "pinyin_numeric": "hao3, na4 wo3 men5 xian1 zhun3 bei4 yi1 xia4. ru2 guo3 guan1 men2 de5 hua4, wo3 men5 jiu4 qu4 bian4 li4 shang1 dian4 mai3 dong1 xi5 chi1.",
          "translation_en": "Okay, let's prepare a bit. If it's closed, we'll go to the convenience store to buy something to eat.",
          "translation_ko": "좋아요, 그럼 먼저 준비 좀 해요. 문을 닫았으면 편의점에 가서 뭐 좀 사 먹어요."
        }
      ],
      "comprehension_questions": [
        {
          "question_en": "What is the backup plan if the first restaurant is closed?",
          "question_ko": "첫 번째 식당이 문을 닫았을 때의 대체 계획은 무엇인가요?",
          "options_en": ["Go home and cook", "Go to a convenience store", "Go to another restaurant"],
          "options_ko": ["집에 가서 요리하다", "편의점에 가다", "다른 식당에 가다"],
          "correct_index": 2
        }
      ],
      "shadowing_prompt": "Repeat each sentence after the speaker, focusing on the conditional structures '如果...的話' and '萬一...的話'.",
      "free_response_prompt": "Say what you will do if your favorite restaurant is closed. Use '如果...的話' or '萬一...的話'."
    }
  ]
}
